    _special_doc(prefix='ni', section='6', title='Cheque', domain='Corporate', act_name='Negotiable Instruments Act, 1881', focus='This provision belongs to the Negotiable Instruments Act, 1881 and is central to cheque transactions, commercial confidence, presumptions in favour of the holder, and summary-style criminal enforcement of dishonoured cheques.', consequence='The key consequence is criminal liability for dishonour of cheque under Section 138, punishable up to two years or fine up to twice the cheque amount, or both, subject to statutory notice and limitation requirements. Presumptions under Sections 118 and 139 significantly affect the burden at trial.', related='Notice requirement, legally enforceable debt, company liability, summary procedure, compounding, and appellate deposit practice', case_law='Indian cheque dishonour jurisprudence focuses on existence of legally enforceable debt, presumptions in favour of the holder, rebuttal by probable defence, and vicarious liability of responsible company officers.', procedure='complainants typically prove the cheque, dishonour memo, statutory notice within time, non-payment within fifteen days, and filing within limitation'),
