    _special_doc(prefix='pca', section='7', title='Public Servant Taking Undue Advantage', domain='Criminal', act_name='Prevention of Corruption Act, 1988', focus='This provision belongs to the Prevention of Corruption Act, 1988 and targets corruption by public servants, abuse of office, illicit gratification, and misuse of official position.', consequence='Consequences include imprisonment, fine, attachment-related investigation consequences, and strong evidentiary focus on demand, acceptance, recovery, and abuse of official position. Procedural approvals and sanction questions frequently shape the case.', related='Trap proceedings, sanction for prosecution, disproportionate assets investigations, and evidentiary presumptions in bribery cases', case_law='Recent jurisprudence continues to insist that mere recovery of tainted money is not enough without proof of demand and acceptance, while Section 17A debates concern legitimate decision-making versus corrupt protection.', procedure='investigations often use complaint verification, trap teams, phenolphthalein tests, digital communications, file movement records, and sanction orders'),
