    _special_doc(prefix='scst', section='Offences', title='Key Atrocity Offences', domain='Criminal', act_name='SC/ST (Prevention of Atrocities) Act, 1989', focus='This provision forms part of the Scheduled Castes and Scheduled Tribes (Prevention of Atrocities) Act, 1989, a stringent protective criminal law intended to deter caste-based violence, humiliation, dispossession, and systemic oppression.', consequence='The Act enhances punishment, creates special courts, restricts anticipatory bail in appropriate cases, and requires sensitised, senior-level investigation into caste-based offences. Relief and rehabilitation measures for victims are also important statutory consequences.', related='Rules under the Act, compensation schedules, witness protection, IPC overlap, and constitutional equality and dignity guarantees', case_law='The Supreme Court has considered anticipatory bail, misuse arguments, and the need to preserve the protective object of the legislation while ensuring fair procedure.', procedure='practice under the Act requires careful identification of caste status, location and context of insult or violence, land or social boycott dimensions, and compliance with special investigation rules'),
