    _special_doc(prefix='labour', section='Minimum Wages', title='Minimum Wages Act, 1948 - Key Protections', domain='Labour', act_name='Indian Labour Laws', focus='This provision belongs to Indian labour and social security law, which sets minimum employment standards, wage security, social insurance, retrenchment conditions, maternity protection, and statutory employment benefits.', consequence='The consequence is statutory entitlement to wages, gratuity, provident fund contributions, retrenchment compensation, maternity benefits, employment injury compensation, bonus, and floor-wage driven compliance. These rights are generally enforced through designated authorities, labour courts, or statutory adjudicatory machinery.', related='Employment contracts, standing orders, labour inspections, social security compliance, service records, and industrial adjudication', case_law='Courts interpret these enactments beneficially in favour of workers while also examining coverage, employee status, continuous service, wage definitions, and statutory exemptions.', procedure='proof usually involves appointment records, wage slips, attendance, PF and ESI contributions, service length, termination notices, and calculation sheets showing the entitlement claimed'),
